#!/usr/bin/env python
import sys

def main():
    n = int(sys.stdin.readline())
    a = [sys.stdin.readline().split() for _ in range(n)]
    ans = -2000000000
    for i in range(n):
        if a[i][1] == "Y":
            if a[i][0] == ">=":
                ans = max(ans, int(a[i][1]))
            elif a[i][0] == "<=":
                ans = min(ans, int(a[i][1]))
            elif a[i][0] == ">":
                ans = max(ans, int(a[i][1]) + 1)
            elif a[i][0] == "<":
                ans = min(ans, int(a[i][1]) - 1)
    for i in range(n):
        if a[i][1] == "N":
            if a[i][0] == ">=":
                ans = max(ans, int(a[i][1]) - 1)
            elif a[i][0] == "<=":
                ans = min(ans, int(a[i][1]) + 1)
            elif a[i][0] == ">":
                ans = max(ans, int(a[i][1]))
            elif a[i][0] == "<":
                ans = min(ans, int(a[i][1]))
    if ans < -2000000000 or ans > 2000000000:
        print("Impossible")
    else:
        print(ans)

if __name__ == "__main__":
    main()
